"""``projects`` router — the canonical CRUD surface, generated by ``build_crud_router``.

A tenant-scoped resource needs no bespoke routes, so the module uses the Tier-C
factory (ADR 0023): it produces the same five secure routes the hand-written
``notes`` router declares — each returning the ``*Read`` DTO, the list paginated —
over the tenant-scoped :class:`ProjectService`. Tenant isolation is unchanged: it
lives in the service's scoped ``base_query`` and the request's bound tenant, not in
the routes.
"""

from __future__ import annotations

from terp.core import build_crud_router

from app.modules.projects.schemas import ProjectCreate, ProjectRead, ProjectUpdate
from app.modules.projects.service import ProjectService

router = build_crud_router(
    ProjectService(),
    read_schema=ProjectRead,
    create_schema=ProjectCreate,
    update_schema=ProjectUpdate,
    tags=["projects"],
)
